import 'dart:convert'; import 'package:http/http.dart' as http; void main() async { var regRes = await http.post(Uri.parse('http://localhost:8080/api/auth/register/phone'), headers: {'Content-Type': 'application/json'}, body: jsonEncode({'phoneNumber': '+998970504204', 'password': 'password123'})); if (regRes.statusCode != 200) return; var token = jsonDecode(regRes.body)['accessToken']; var res = await http.get(Uri.parse('http://localhost:8080/api/fines/count'), headers: {'Authorization': 'Bearer ' + token}); print('Fines: ' + res.statusCode.toString() + ' ' + res.body); }
